export const getSearchUrl = (params: SearchParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/search?${stringifiedParams}` : `/api/search`
}

/**
 * @summary Search all content
 */
export const search = async (params: SearchParams, options?: RequestInit): Promise<Content[]> => {

  return customFetch<Content[]>(getSearchUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





export const getSearchQueryKey = (params?: SearchParams,) => {
    return [
    `/api/search`, ...(params ? [params] : [])
    ] as const;
    }


